[
  {
    "idea": "A surge in new patent applications filed by semiconductor companies signals upcoming tech innovation bursts.",
    "data": {
      "source": "USPTO Patent Application Bulk Data",
      "type": "api",
      "frequency": "weekly",
      "stable": true
    },
    "behavior": "An unusual weekly increase in semiconductor-related patent filings often precedes accelerated product releases and revenue growth.",
    "market_impact": {
      "direction": "bullish",
      "sector": "XLK",
      "rationale": "Technology sector ETFs, especially semiconductor-heavy ones, benefit from innovation cycles driven by new patents."
    },
    "trade_logic": {
      "entry": "If weekly patent filings for semiconductor companies increase by over 20% compared to the previous 4-week average",
      "exit": "After 15 trading days or if weekly filings fall below the previous 4-week average",
      "expected_frequency": "medium"
    }
  }
]
